func trackHandler(w http.ResponseWriter, r *http.Request) {
	start := time.Now()

	userID := r.URL.Query().Get("user_id")
	if userID == "" {
		userID = "unknown"
	}

	requestID := r.URL.Query().Get("request_id")
	if requestID == "" {
		requestID = strconv.FormatInt(time.Now().UnixNano(), 10)
	}

	path := r.URL.Query().Get("path")
	if path == "" {
		path = r.URL.Path
	}

	method := r.URL.Query().Get("method")
	if method == "" {
		method = r.Method
	}

	status := r.URL.Query().Get("status")
	if status == "" {
		status = "200"
	}

	userActive.WithLabelValues(userID).Set(1)
	requestsTotal.WithLabelValues(userID, requestID, path, method, status).Inc()
	requestDuration.WithLabelValues(userID, requestID, path, method, status).Observe(time.Since(start).Seconds())

	w.WriteHeader(http.StatusOK)
	_, _ = w.Write([]byte("tracked"))
}